package org.eclipse.rdf4j.testsuite.sparql.tests;

import static org.assertj.core.api.Assertions.assertThat;

import java.io.StringReader;
import java.util.List;
import java.util.function.Supplier;
import java.util.stream.Stream;

import org.eclipse.rdf4j.query.BindingSet;
import org.eclipse.rdf4j.query.QueryLanguage;
import org.eclipse.rdf4j.query.QueryResults;
import org.eclipse.rdf4j.query.TupleQuery;
import org.eclipse.rdf4j.query.TupleQueryResult;
import org.eclipse.rdf4j.repository.Repository;
import org.eclipse.rdf4j.repository.RepositoryConnection;
import org.eclipse.rdf4j.rio.RDFFormat;
import org.eclipse.rdf4j.testsuite.sparql.AbstractComplianceTest;
import org.junit.jupiter.api.DynamicTest;

/**
 * Tests on LATERAL variable scope behavior.
 */
public class LateralScopeTest extends AbstractComplianceTest {

	public LateralScopeTest(Supplier<Repository> repo) {
		super(repo);
	}

	private void testLateralSubSelectWithSiblingFilterDoesNotSeeHiddenOuterVariable(RepositoryConnection conn)
			throws Exception {
		String data = "@prefix ex: <http://example.org/> .\n"
				+ "@prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#> .\n"
				+ "\n"
				+ "ex:subject1 ex:predicate ex:object1 .\n"
				+ "ex:subject1 rdfs:label \"Label 1\" .\n"
				+ "ex:subject2 ex:predicate ex:object2 .\n"
				+ "ex:subject2 rdfs:label \"Label 2\" .\n"
				+ "ex:subject3 ex:predicate ex:object3 .\n"
				+ "ex:subject3 rdfs:label \"Label 3\" .\n";

		String query = "PREFIX ex: <http://example.org/>\n"
				+ "PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>\n"
				+ "\n"
				+ "SELECT * {\n"
				+ "   ?s ex:predicate ?o\n"
				+ "   LATERAL {\n"
				+ "      { SELECT ?label { ?s rdfs:label ?label } ORDER BY ?label LIMIT 1 }\n"
				+ "      FILTER(?label = \"Label 1\")\n"
				+ "   }\n"
				+ "}\n";

		conn.add(new StringReader(data), "", RDFFormat.TURTLE);

		TupleQuery tq = conn.prepareTupleQuery(QueryLanguage.SPARQL, query);

		try (TupleQueryResult result = tq.evaluate()) {
			List<BindingSet> results = QueryResults.asList(result);
			assertThat(results).hasSize(3);
			assertThat(results).allSatisfy(bs -> assertThat(bs.getValue("label").stringValue()).isEqualTo("Label 1"));
		}
	}

	public Stream<DynamicTest> tests() {
		return Stream.of(makeTest("LateralSubSelectWithSiblingFilterDoesNotSeeHiddenOuterVariable",
				this::testLateralSubSelectWithSiblingFilterDoesNotSeeHiddenOuterVariable));
	}
}
